<?php/DevelopmentErrorReportingif(!defined('DEVELOPMENT_MODE')){error_reporting(E_ALL);ini_set('display_errors',1);ini_set('display_startup_errors',1);}declare(strict_types=1);/***StandardizedAPIResponseHelper*/classApiResponse{constHTTP_OK=200;constHTTP_CREATED=201;constHTTP_BAD_REQUEST=400;constHTTP_UNAUTHORIZED=401;constHTTP_FORBIDDEN=403;constHTTP_NOT_FOUND=404;constHTTP_INTERNAL_ERROR=500;/***SendstandardizedJSONresponse*/publicstaticfunctionjson($success,$data=null,$message='',$statusCode=200){http_response_code($statusCode);header('Content-Type:application/json;charset=UTF-8');header('Access-Control-Allow-Origin:*');header('Access-Control-Allow-Methods:GET,POST,PUT,DELETE,OPTIONS');header('Access-Control-Allow-Headers:Content-Type,Authorization');$response=['success'=>$success,'message'=>$message,'data'=>$data,'timestamp'=>date('Y-m-d\TH:i:s\Z'),'request_id'=>uniqid('req_',true)];/Removenulldatafromresponseif($data===null){unset($response['data']);}echojson_encode($response,JSON_PRETTY_PRINT|JSON_UNESCAPED_UNICODE);exit;}/***Successresponse*/publicstaticfunctionsuccess($data=null,$message='Operationsuccessful'){self::json(true,$data,$message,self::HTTP_OK);}/***Createdresponse*/publicstaticfunctioncreated($data=null,$message='Resourcecreatedsuccessfully'){self::json(true,$data,$message,self::HTTP_CREATED);}/***Errorresponse*/publicstaticfunctionerror($message='Anerroroccurred',$statusCode=400,$data=null){self::json(false,$data,$message,$statusCode);}/***Validationerror*/publicstaticfunctionvalidationError($errors,$message='Validationfailed'){self::json(false,['errors'=>$errors],$message,self::HTTP_BAD_REQUEST);}/***Notfound*/publicstaticfunctionnotFound($message='Resourcenotfound'){self::json(false,null,$message,self::HTTP_NOT_FOUND);}/***Unauthorized*/publicstaticfunctionunauthorized($message='Unauthorizedaccess'){self::json(false,null,$message,self::HTTP_UNAUTHORIZED);}/***Servererror*/publicstaticfunctionserverError($message='Internalservererror'){self::json(false,null,$message,self::HTTP_INTERNAL_ERROR);}/***Paginatedresponse*/publicstaticfunctionpaginated($data,$page,$limit,$total,$message='Dataretrievedsuccessfully'){$totalPages=ceil($total/$limit);$response=['items'=>$data,'pagination'=>['current_page'=>(int)$page,'per_page'=>(int)$limit,'total_items'=>(int)$total,'total_pages'=>(int)$totalPages,'has_next'=>$page<$totalPages,'has_prev'=>$page>1]];self::json(true,$response,$message,self::HTTP_OK);}/***HandleAPIauthentication*/publicstaticfunctioncheckApiAuth(){session_start();if(!isset($_SESSION['logged_in'])||$_SESSION['logged_in']!==true){self::unauthorized('Authenticationrequired');}}/***Validaterequiredfields*/publicstaticfunctionvalidateRequired($data,$requiredFields){$missing=[];forforeach($requiredFieldsas$field){if(!isset($data[$field])||empty($data[$field])){$missing[]=$field;}}if(!empty($missing)){self::validationError(array_fill_keys($missing,'Thisfieldisrequired'),'Missingrequiredfields:'.implode(',',$missing));}}/***GetJSONinput*/publicstaticfunctiongetJsonInput(){$json=file_get_contents('php://input');$data=json_decode($json,true);if(json_last_error()!==JSON_ERROR_NONE){self::error('InvalidJSONformat',self::HTTP_BAD_REQUEST);}return$data??[];}}?>
